# Weekly capacity report: automated Monday pre-standup Slack post
from dataclasses import dataclass, field
from typing import Dict, List
import json, urllib.request

@dataclass
class ModelCapacityStatus:
    model: str
    current_util_pct: float
    runway_days: float | None     # None = demand flat/falling
    open_jira_key: str | None     # existing provisioning ticket

    @property
    def status_emoji(self) -> str:
        if self.runway_days is None or self.runway_days > 60:
            return ':large_green_circle:'
        elif self.runway_days > 30:
            return ':large_yellow_circle:'
        elif self.runway_days > 14:
            return ':warning:'
        return ':red_circle:'

    def to_slack_line(self) -> str:
        runway_str = (
            'flat' if self.runway_days is None
            else f'{self.runway_days:.0f}d'
        )
        jira = f' [{self.open_jira_key}]' if self.open_jira_key else ''
        return (
            f'{self.status_emoji} *{self.model}*: '
            f'util={self.current_util_pct:.0f}%, runway={runway_str}{jira}'
        )

def post_weekly_report(statuses: List[ModelCapacityStatus], webhook: str):
    needs_action = [s for s in statuses
                    if s.runway_days is not None and s.runway_days < 30]
    lines = ['*Weekly GenAI Capacity Review*', '']
    for s in sorted(statuses,
                    key=lambda x: x.runway_days or 9999):
        lines.append(s.to_slack_line())
    if needs_action:
        lines += ['', '*Action required:*']
        for s in needs_action:
            ticket = s.open_jira_key or 'OPEN NEW TICKET'
            lines.append(f'  - {s.model}: runway {s.runway_days:.0f}d -> {ticket}')
    payload = json.dumps({'text': chr(10).join(lines)}).encode()
    req = urllib.request.Request(
        webhook, data=payload,
        headers={'Content-Type': 'application/json'}
    )
    urllib.request.urlopen(req)

# Headroom calculation: how much spare capacity to target at each review cadence
from dataclasses import dataclass
from typing import Optional

@dataclass
class HeadroomPlan:
    model: str
    current_capacity_toks_per_s: float
    p80_forecast_30d: float    # 80th-percentile upper bound at 30d
    p80_forecast_90d: float    # 80th-percentile upper bound at 90d
    burst_multiplier: float = 1.25  # +25% for feature launch buffer

    @property
    def target_capacity_30d(self) -> float:
        # Provision so P80 forecast fits within 70% of capacity
        # i.e. capacity >= forecast / 0.70
        return self.p80_forecast_30d / 0.70

    @property
    def target_capacity_90d(self) -> float:
        return self.p80_forecast_90d / 0.70

    @property
    def shortfall_30d(self) -> float:
        return max(0.0, self.target_capacity_30d - self.current_capacity_toks_per_s)

    @property
    def shortfall_90d(self) -> float:
        return max(0.0, self.target_capacity_90d - self.current_capacity_toks_per_s)

    def gpus_needed(self, toks_per_s_per_gpu: float) -> int:
        '''Additional A100s required to close 90d shortfall.'''
        return max(0, int(self.shortfall_90d / toks_per_s_per_gpu) + 1)

# Example usage:
plan = HeadroomPlan(
    model='llama3-70b',
    current_capacity_toks_per_s=4800,  # 4 x A100 at 1200 tok/s
    p80_forecast_30d=3600,
    p80_forecast_90d=5800,
)
print(f'30d shortfall: {plan.shortfall_30d:.0f} tok/s')
print(f'90d shortfall: {plan.shortfall_90d:.0f} tok/s')
print(f'A100s to request: {plan.gpus_needed(toks_per_s_per_gpu=1200)}')
# 30d shortfall: 0 tok/s   (we are 4800, target is 3600/0.70 = 5142 -- 342 short)
# 90d shortfall: 1114 tok/s
# A100s to request: 1

# Quarterly cost-efficiency report: $ per million output tokens per model
from dataclasses import dataclass

@dataclass
class ModelCostProfile:
    model: str
    gpu_count: int
    gpu_hourly_rate_usd: float   # reserved rate
    mean_output_toks_per_s: float

    @property
    def cost_per_million_output_tokens(self) -> float:
        toks_per_hour = self.mean_output_toks_per_s * 3600
        gpu_cost_per_hour = self.gpu_count * self.gpu_hourly_rate_usd
        return (gpu_cost_per_hour / toks_per_hour) * 1_000_000

    def format_line(self) -> str:
        return (
            f'{self.model}: '
            f'${self.cost_per_million_output_tokens:.2f}/1M tok '
            f'(util={self.mean_output_toks_per_s / (self.gpu_count * 1200) * 100:.0f}%)'
        )

# Quarterly review comparison: measure before/after distillation or right-sizing
profiles = [
    ModelCostProfile('llama3-70b',  4, 1.80, 800),   # $0.003/1M tok
    ModelCostProfile('llama3-8b',   1, 1.80, 3500),  # $0.0001/1M tok (35x cheaper)
    ModelCostProfile('mistral-7b',  1, 1.80, 4000),  # batch embedding use case
]
for p in profiles:
    print(p.format_line())
